        if n == 0:
            return 0
        elif n == 1:
            return 0
        elif n == 2:
            return 2
        elif n == 3:
            return 0
        elif n == 4:
            return 2
        else:
            return fib4_recursive(n-1) + fib4_recursive(n-2) + fib4_recursive(n-3) + fib4_recursive(n-4)

    return fib4_recursive(n)
