def encode(message):
    """
    Write a function that takes a message, and encodes in such a way that it swaps case 
    of all letters, replaces all vowels in the message with the letter that appears 2 places ahead of that vowel in 
    the english alphabet.

    Assume only letters. 

    Examples:
    >>> encode('test')
    'TGST'
    >>> encode('This is a message')
    'tHKS KS C MGSSCGG'
    """
    vowels = 'aeiouAEIOU'
    swapped = []
    for char in message:
        if char.isalpha():
            if char.isupper():
                swapped.append(char.lower())
            else:
                swapped.append(char.upper())
        else:
            if char in vowels:
                pos = (vowels.find(char) - 2) % 26
                swapped.append(vowels[pos])
            else:
                swapped.append(char)
    return ''.join(swapped)
